import { create } from 'zustand'

// Globale Filter laut CLAUDE.md §7 — werden auf jedem Spielmodus-Screen
// in der WHERE-Clause der Card-Loader-Query angewendet. Kategorien sind
// in Sprint 3 noch nur fürs Filter-Dropdown — die Game-Loader nutzen sie
// ab Sprint 4.

export type Category =
  | 'all'
  | 'anamnese'
  | 'anatomie'
  | 'symptome'
  | 'krankheiten'
  | 'pharma'
  | 'untersuchung'
  | 'gynaekologie'
  | 'verb'
  | 'adjektiv'
  | 'phrase'

export type WordClass =
  | 'all'
  | 'noun'
  | 'verb'
  | 'adjective'
  | 'phrase'
  | 'question'

export type Difficulty = 'all' | 'easy' | 'medium' | 'hard'

export type MasteryStatus = 'all' | 'unmastered' | 'mastered' | 'production_mastered'

// Abfrage-Richtung: hu_to_de = HU vorne / Frage, DE hinten / Antwort (Default)
//                  de_to_hu = DE vorne / Frage, HU hinten / Antwort (härter)
export type Direction = 'hu_to_de' | 'de_to_hu'

type FilterState = {
  category: Category
  wordClass: WordClass
  difficulty: Difficulty
  mastery: MasteryStatus
  direction: Direction
  setCategory: (c: Category) => void
  setWordClass: (w: WordClass) => void
  setDifficulty: (d: Difficulty) => void
  setMastery: (m: MasteryStatus) => void
  setDirection: (d: Direction) => void
  reset: () => void
}

export const useFilterStore = create<FilterState>((set) => ({
  category: 'all',
  wordClass: 'all',
  difficulty: 'all',
  mastery: 'all',
  direction: 'hu_to_de',
  setCategory: (category) => set({ category }),
  setWordClass: (wordClass) => set({ wordClass }),
  setDifficulty: (difficulty) => set({ difficulty }),
  setMastery: (mastery) => set({ mastery }),
  setDirection: (direction) => set({ direction }),
  reset: () => set({ category: 'all', wordClass: 'all', difficulty: 'all', mastery: 'all', direction: 'hu_to_de' })
}))
